create table if not exists observation_summary (summary_id text primary key, source text not null check(source='ble'), collector_run_id text not null, device_token text not null, window_start text not null, window_end text not null, first_observed_at text not null, last_observed_at text not null, sample_count integer not null check(sample_count>=0), median_rssi_dbm integer not null, max_rssi_dbm integer not null, frequency_mhz real, tx_power_dbm integer, unique(source, summary_id));
create table if not exists source_watermark (source text primary key check(source='ble'), collector_run_id text not null, boot_id text not null, caught_up_through text not null, spool_sequence integer not null check(spool_sequence>=0), health text not null check(health in ('healthy','degraded','recovering','unavailable')), updated_at text not null, updated_boottime_ns integer not null check(updated_boottime_ns>=0), progress_sequence integer not null check(progress_sequence>=0));
create table if not exists collector_run (collector_run_id text primary key, boot_id text not null, pid integer not null check(pid>0), started_at text not null, ended_at text);
create table if not exists collector_error (id integer primary key, collector_run_id text, code text not null, message text not null, occurred_at text not null, foreign key(collector_run_id) references collector_run(collector_run_id));
